// SceneDelegate.swift
import UIKit

class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?

    func scene(_ scene: UIScene,
               willConnectTo session: UISceneSession,
               options connectionOptions: UIScene.ConnectionOptions) {

        guard let windowScene = (scene as? UIWindowScene) else { return }

        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = rootController()
        window?.makeKeyAndVisible()
    }

    private func rootController() -> UIViewController {
        if SessionManager.shared.isAuthenticated {
            return MainViewController()
        } else {
            return UINavigationController(rootViewController: LoginViewController())
        }
    }
}


// LoginViewController.swift
import UIKit

final class LoginViewController: UIViewController {

    private let passwordField = UITextField()
    private let loginButton   = UIButton(type: .system)
    private let retryButton   = UIButton(type: .system)

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "Login"

        setupViews()
    }

    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        attemptBiometricAuth()
    }

    private func setupViews() {
        passwordField.placeholder = "Password"
        passwordField.isSecureTextEntry = true
        passwordField.borderStyle = .roundedRect

        loginButton.setTitle("Login", for: .normal)
        loginButton.addTarget(self, action: #selector(handlePasswordLogin), for: .touchUpInside)

        retryButton.setTitle("Use Face ID / Touch ID", for: .normal)
        retryButton.addTarget(self, action: #selector(attemptBiometricAuth), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [passwordField, loginButton, retryButton])
        stack.axis = .vertical
        stack.spacing = 16
        stack.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24)
        ])
    }

    @objc private func handlePasswordLogin() {
        guard validatePassword() else {
            presentAlert(title: "Error", message: "Invalid password.")
            return
        }
        completeAuthentication()
    }

    @objc private func attemptBiometricAuth() {
        let reason = BiometricAuthManager.shared.biometricType == .faceID
        ? "Authenticate with Face ID"
        : "Authenticate with Touch ID"
        BiometricAuthManager.shared.authenticate(reason: reason) { [weak self] success, error in
            guard let self = self else { return }

            if success {
                self.completeAuthentication()
            } else {
                self.presentRetryAlert(error: error)
            }
        }
    }

    private func presentRetryAlert(error: Error?) {
        let message = error?.localizedDescription ?? "Authentication failed."
        let ac = UIAlertController(title: "Biometric Authentication", message: message, preferredStyle: .alert)
        ac.addAction(UIAlertAction(title: "Try Again", style: .default) { _ in
            self.attemptBiometricAuth()
        })
        ac.addAction(UIAlertAction(title: "Enter Password", style: .default))
        present(ac, animated: true)
    }

    private func completeAuthentication() {
        SessionManager.shared.isAuthenticated = true
        transitionToMain()
    }

    private func transitionToMain() {
        let mainVC = MainViewController()
        if let window = view.window {
            window.rootViewController = mainVC
            UIView.transition(with: window, duration: 0.3, options: .transitionFlipFromRight, animations: nil)
        }
    }

    private func validatePassword() -> Bool {
        // Replace with real validation
        return passwordField.text == "password123"
    }

    private func presentAlert(title: String, message: String) {
        let ac = UIAlertController(title: title, message: message, preferredStyle: .alert)
        ac.addAction(UIAlertAction(title: "OK", style: .default))
        present(ac, animated: true)
    }
}


// MainViewController.swift
import UIKit

final class MainViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemGreen
        title = "Home"

        navigationItem.rightBarButtonItem =
            UIBarButtonItem(title: "Logout", style: .plain, target: self, action: #selector(logout))
    }

    @objc private func logout() {
        SessionManager.shared.reset()
        if let window = view.window {
            window.rootViewController = UINavigationController(rootViewController: LoginViewController())
            UIView.transition(with: window, duration: 0.3, options: .transitionFlipFromLeft, animations: nil)
        }
    }
}